class Solution(object):
    def maxProduct(self, nums):
        B = 20  # nums[i] <= 10^6 < 2^20
        FULL = (1 << B) - 1
        # dp[mask] = max value in nums that is a submask of mask
        dp = [0] * (1 << B)
        for v in nums:
            dp[v] = max(dp[v], v)
        # SOS (Sum over Subsets) DP to propagate max to supermasks
        for bit in range(B):
            for mask in range(1 << B):
                if mask & (1 << bit):
                    dp[mask] = max(dp[mask], dp[mask ^ (1 << bit)])

        ans = 0
        for v in nums:
            complement = (~v) & FULL
            partner = dp[complement]
            ans = max(ans, v * partner)
        return ans
